import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

public class Main {

    public static void main(String[] args) {
        List<Employee> listEmployee = new ArrayList<>();
        listEmployee.add(new Employee(1L, "Ali", "IT", "Bucharest", 5000));
        listEmployee.add(new Employee(2L, "Ayse", "HR", "Cluj", 4000));
        listEmployee.add(new Employee(3L, "Mehmet", "IT", "Iasi", 5500));
        listEmployee.add(new Employee(4L, "Zeynep", "Finance", "Bucharest", 6000));

        Map<String, List<String>> listMap = groupEmployeesByDepartment(listEmployee);

        for (Map.Entry<String, List<String>> entry : listMap.entrySet()) {
            System.out.print(entry.getKey());
            System.out.println(entry.getValue());
        }
    }

    static Map<String, List<String>> groupEmployeesByDepartmentAlternative(List<Employee> employees) {

        Map<String, List<String>> result = employees.stream()
                .collect(Collectors.groupingBy(
                        Employee::getDepartment, // 1. Kural: Departmana göre grupla (Key)
                        Collectors.mapping( // 2. Kural: Grubun içine neyi koyayım?
                                Employee::getName, // Sadece ismi al
                                Collectors.toList() // Ve liste olarak sakla (Value)
                        )));

        return result;
    }

    static Map<String, List<String>> groupEmployeesByDepartmentAlternative2(List<Employee> employees) {

        Map<String, List<String>> result = employees.stream()
                .collect(Collectors.groupingBy(
                        (employee) -> employee.getDepartment(), // 1. Kural: Departmana göre grupla (Key)
                        Collectors.mapping( // 2. Kural: Grubun içine neyi koyayım?
                                (employee) -> employee.getName(), // Sadece ismi al
                                Collectors.toList() // Ve liste olarak sakla (Value)
                        )));

        return result;
    }

    static Map<String, List<String>> groupEmployeesByDepartment(List<Employee> employees) {

        Map<String, List<String>> map = new HashMap<>();

        employees.stream().forEach((employee) -> {
            List<String> list = map.getOrDefault(employee.getDepartment(), null);
            if (list == null) {
                list = new ArrayList<>();
            }
            list.add(employee.getName());
            map.put(employee.getDepartment(), list);

        });
        return map;
    }
}

