import java.util.ArrayList;
import java.util.List;
import java.util.stream.Collectors;

public class Main {
    public static void main(String[] args) {
        List<Product> listProduct = new ArrayList<>();

        listProduct.add(new Product(1L, "Keyboard", 100d));
        listProduct.add(new Product(2L, "Mouse", 50d));
        listProduct.add(new Product(3L, "Monitor", 100d));
        listProduct.add(new Product(4L, "Cable", 20d));

        List<Product> listSorted = sortProducts(listProduct);

        System.out.println(listSorted.toString());

    }

    static List<Product> sortProducts(List<Product> products) {

        return products.stream().sorted((a, b) -> {
            int result = (int) (a.getPrice() - b.getPrice());
            if (result == 0) {
                return a.getName().compareToIgnoreCase(b.getName());
            }

            return result;
        }).collect(Collectors.toList());
    }
}




