import java.util.ArrayList;
import java.util.Arrays;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

public class Main {
    public static void main(String[] args) {
        List<String> value = new ArrayList<>(Arrays.asList("apple", "banana", "apple", "orange", "banana", "grape"));
        List<String> removed = removeDuplicatesPreserveOrder(value);

        System.out.println(removed.toString());
    }

    static List<String> removeDuplicatesPreserveOrder(List<String> items){

        Set<String> linkedItems = new LinkedHashSet<>();

        for(String item : items)
        {
            linkedItems.add(item);
        }

        return linkedItems.stream().collect(Collectors.toList());
    }
}

